// Función para transformar el payload en la estructura deseada
function transformarPayload(payload) {
    let niveles = [];

    // Mapeamos cada lista de datos por timestamp (ts)
    let map = {};

    // Función auxiliar para agrupar los datos
    function agregarDato(campo, key) {
        for (let i = 0; i < campo.length; i++) {
            let ts = campo[i].ts;
            if (!map[ts]) {
                map[ts] = { ts: ts };  // Crear un nuevo objeto si no existe
            }
            map[ts][key] = campo[i].value;  // Añadir valor al campo correspondiente
        }
    }

    // Llenamos el mapa con los datos del payload
    agregarDato(payload.Cliente, 'Cliente');
    agregarDato(payload.Modelo, 'Modelo');
    agregarDato(payload.NumNivel, 'NumNivel');
    agregarDato(payload.Cota, 'CotaInferior');
    agregarDato(payload.FechaInicio, 'FechaInicio');
    agregarDato(payload.FechaFin, 'FechaFin');
    agregarDato(payload.Activo, 'Activo');

    // Creamos la lista de niveles a partir del mapa
    for (let ts in map) {
        let nivel = {
            Cliente: map[ts].Cliente,
            Modelo: map[ts].Modelo,
            NumNivel: parseInt(map[ts].NumNivel),
            CotaInferior: parseFloat(map[ts].CotaInferior),
            FechaInicio: map[ts].FechaInicio,
            FechFin: map[ts].FechaFin || "",  // Dejar vacío si no hay FechaFin
            Activo: parseInt(map[ts].Activo)
        };
        niveles.push(nivel);
    }

    return niveles;
}

